/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_support.h"

//// Convolution Functions

int32_t riscv_nn_conv_dw_HWC_u8_u8_u8_asym_bias_any(const uint8_t * in_tensor,
                                                    const uint16_t in_tensor_dim_x,
                                                    const uint16_t in_tensor_dim_y,
                                                    const uint16_t in_tensor_ch,
                                                    const uint8_t * ker_weight,
                                                    const uint16_t ker_dim_x,
                                                    const uint16_t ker_dim_y,
                                                    const int16_t ch_mult,
                                                    const int16_t pad_x,
                                                    const int16_t pad_y,
                                                    const int16_t stride_x,
                                                    const int16_t stride_y,
                                                    const int16_t dilation_x,
                                                    const int16_t dilation_y,
                                                    const int32_t * bias,
                                                    const int32_t in_offset,    //assume (in + offset) is in the range of int16
                                                    const int32_t ker_offset,   //assume (kernel + offset) is in the range of int16
                                                    const int32_t out_offset,   //assume (output + offset) is in the range of int16
                                                    uint8_t * out_tensor,
                                                    const uint16_t out_tensor_dim_x,
                                                    const uint16_t out_tensor_dim_y,
                                                    const int32_t act_min,
                                                    const int32_t act_max,
                                                    const int32_t out_shift,
                                                    const int32_t out_scale)
{
    int32_t status = 0;

#ifdef ENA_EMPTY_FUN
    //empty body
#else
    //check input constraints
    if((ch_mult & 1) || (ker_dim_x & 1))
    {
        return -1;
    }
    //to be checked: it seems pad_x must be even
    // if(pad_x & 1)
    // {
    //     return 1;
    // }
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
    long vl;
    long out_shift2 = 30 - out_shift;

    for (long i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        long base_idx_y = (i_out_y * stride_y) - pad_y;
        // ker_weight start position: (base_idx_y + ker_y_start) >= 0
        long ker_y_start = MAX(0, -base_idx_y);
        // ker_weight end position: (base_idx_y + ker_y_end) < in_tensor_dim_y
        long ker_y_end = MIN(ker_dim_y, in_tensor_dim_y - base_idx_y);

        for (long i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            long base_idx_x = (i_out_x * stride_x) - pad_x;
            // ker_weight start position: (base_idx_x + ker_x_start) >= 0
            long ker_x_start = MAX(0, -base_idx_x);
            // ker_weight end position: (base_idx_x + ker_x_end) < in_tensor_dim_x
            long ker_x_end = MIN(ker_dim_x, in_tensor_dim_x - base_idx_x);

            int32_t *bias2 = (int32_t *)bias;

            for (long i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
            {
                long i_ch_mult = 0;
                int ch_mult_rest = ch_mult;
                for (; i_ch_mult < ch_mult; i_ch_mult += vl)
                {
                    long idx_out_ch = i_ch_mult + i_input_ch * ch_mult;
                    vl = __riscv_vsetvl_e32m8(ch_mult_rest);
                    vint32m8_t vBias2 = __riscv_vle32_v_i32m8(bias2, vl);
                    bias2 += vl;

                    vl = __riscv_vsetvl_e16m4(ch_mult_rest);
                    for (long i_ker_y = ker_y_start; i_ker_y < ker_y_end; i_ker_y++)
                    {
                        long idx_y = base_idx_y + i_ker_y;
                        long ker_idx_0 = (i_ker_y * ker_dim_x + ker_x_start) * (in_tensor_ch * ch_mult) + idx_out_ch;
                        uint8_t *kernel_ptr = (uint8_t *)&ker_weight[ker_idx_0];

                        long idx_x = base_idx_x + ker_x_start;
                        long idx_0 = (idx_y * in_tensor_dim_x + idx_x) * in_tensor_ch + i_input_ch;
                        uint8_t *in_ptr = (uint8_t *)&in_tensor[idx_0];
                        long i_ker_x;
                        for (i_ker_x = ker_x_start; i_ker_x < ker_x_end; i_ker_x++)
                        {
                            long in = *in_ptr + in_offset;
                            vuint8m2_t vKernelPtr = __riscv_vle8_v_u8m2(kernel_ptr, vl);
                            vuint16m4_t vKernelPtrExt = __riscv_vzext_vf2(vKernelPtr, vl);
                            vKernelPtrExt = __riscv_vadd(vKernelPtrExt, ker_offset, vl);
                            vint16m4_t vKernelPtrExtSigned = __riscv_vreinterpret_i16m4(vKernelPtrExt);
                            vBias2 = __riscv_vwmacc(vBias2, in, vKernelPtrExtSigned, vl);
                            in_ptr += in_tensor_ch;
                            kernel_ptr += in_tensor_ch * ch_mult;
                        }
                    }

                    vl = __riscv_vsetvl_e32m8(ch_mult_rest);

                    //requantization
                    //part-1
                    long vl2;
                    vl2 = __riscv_vsetvl_e32m4(ch_mult_rest);
                    vint32m4_t vBias2Part1 = __riscv_vget_i32m4(vBias2, 0);
                    vint64m8_t vOutTensorPart1 = __riscv_vwmul(vBias2Part1, out_scale, vl2);

